#include <stdio.h>
#include <string.h>
#define MAX 100000
#define V 10
#define E 15
int adj[V][V];
void dfs(int u, int v, char *s, int len, int *walk, int *idx) {
    if (*idx == len) {
        for (int i = 0; i <= *idx; i++) {
            printf("%d", walk[i]);
        }
        printf("\n");
        return;
    }
    for (int i = 0; i < V; i++) {
        if (adj[v][i] && s[*idx] == 'A' + i) {
            walk[*idx + 1] = i;
            (*idx)++;
            dfs(u, i, s, len, walk, idx);
            (*idx)--;
        }
    }
}
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        char s[MAX + 1];
        scanf("%s", s);
        int len = strlen(s);
        int walk[MAX + 1];
        int idx = 0;
        walk[0] = 0;
        dfs(0, 0, s, len, walk, &idx);
    }
    return 0;
}

