import java.util.Scanner;
public class Main {
    static final int MAX = 100000;
    static final int V = 10;
    static final int E = 15;
    static int[][] adj = new int[V][V];
    public static void dfs(int u, int v, String s, int len, int[] walk, int[] idx) {
        if (idx[0] == len) {
            for (int i = 0; i <= idx[0]; i++) {
                System.out.print(walk[i]);
            }
            System.out.println();
            return;
        }
        for (int i = 0; i < V; i++) {
            if (adj[v][i] && s.charAt(idx[0]) == 'A' + i) {
                walk[idx[0] + 1] = i;
                idx[0]++;
                dfs(u, i, s, len, walk, idx);
                idx[0]--;
            }
        }
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt();
        while (t-- > 0) {
            String s = sc.next();
            int len = s.length();
            int[] walk = new int[MAX + 1];
            int[] idx = new int[1];
            walk[0] = 0;
            dfs(0, 0, s, len, walk, idx);
        }
    }
}

